import json, re

# Access stored results directly 
clinical_result = var_functions.query_db:76
mutation_result = var_functions.query_db:44

# Parse clinical data for BRCA patients
brca_data = []
for rec in clinical_result:
    desc = rec.get('Patient_description', '')
    hist = rec.get('histological_type', '')
    match = re.search(r'(TCGA-\w+-\w+)', desc)
    if match:
        brca_data.append({
            'barcode': match.group(1),
            'hist_type': hist.strip() if hist else 'Unknown'
        })

# Parse CDH1 mutations
cdh1_set = set(m['ParticipantBarcode'] for m in mutation_result)

# Combine and analyze
hist_dict = {}
for patient in brca_data:
    hist = patient['hist_type']
    has_cdh1 = patient['barcode'] in cdh1_set

    if hist not in hist_dict:
        hist_dict[hist] = {'mut': 0, 'not_mut': 0}

    if has_cdh1:
        hist_dict[hist]['mut'] += 1
    else:
        hist_dict[hist]['not_mut'] += 1

# Filter and calculate
filtered = {h: v for h, v in hist_dict.items() if (v['mut'] + v['not_mut']) > 10}

# Calculate chi-square
def calc_chi(contingency):
    row_tot = [sum(r) for r in contingency]
    col_tot = [sum(r[0] for r in contingency), sum(r[1] for r in contingency)]
    grand = sum(row_tot)
    chi2 = 0.0
    for i in range(len(contingency)):
        for j in range(2):
            obs = contingency[i][j]
            exp = (row_tot[i] * col_tot[j]) / grand
            if exp > 0:
                chi2 += ((obs - exp) ** 2) / exp
    return chi2

if len(filtered) >= 2:
    cont_table = [[v['mut'], v['not_mut']] for v in filtered.values()]
    chi_val = calc_chi(cont_table)
    p_val = "<0.05" if chi_val > 3.84 else ">=0.05"

    result = {
        'patients': len(brca_data),
        'cdh1_mut': sum(v['mut'] for v in hist_dict.values()),
        'chi_sq': chi_val,
        'p': p_val,
        'table': filtered
    }
else:
    result = {'error': 'Insufficient data after filtering'}

print('__RESULT__:')
print(json.dumps(result))

